    var obsText = obsolete != null ? $" [OBSOLETE: {obsolete.Message?.Substring(0, Math.Min(80, obsolete.Message.Length))}...]" : "";
    Console.WriteLine($"{m.Name}{genArgs}({pars}){obsText}");
}
EOF
